// src/components/ImageModal.jsx
import React, { useEffect, useRef } from "react";
import ReactModal from "react-modal";
//import OpenSeadragon from "openseadragon";
import "./ImageModal.css";

useEffect(() => {
  if (isOpen && viewerRef.current && imageUrl && window.OpenSeadragon) {
    if (osdInstanceRef.current) {
      osdInstanceRef.current.destroy();
    }

    osdInstanceRef.current = window.OpenSeadragon({
      element: viewerRef.current,
      prefixUrl: "/openseadragon/images/",
      tileSources: imageUrl,  // or your test .dzi URL
      showNavigator: true,
      defaultZoomLevel: 1,
      minZoomLevel: 0.5,
      maxZoomLevel: 10,
    });
  }

  return () => {
    if (osdInstanceRef.current) {
      osdInstanceRef.current.destroy();
      osdInstanceRef.current = null;
    }
  };
}, [isOpen, imageUrl]);

ReactModal.setAppElement("#root");

export default function ImageModal({ isOpen, onRequestClose, imageUrl }) {
  const viewerRef = useRef(null);
  const osdInstanceRef = useRef(null);

  useEffect(() => {
    console.log("ImageModal received imageUrl:", imageUrl);

    if (isOpen && viewerRef.current && imageUrl) {
      // Cleanup previous instance if present
      if (osdInstanceRef.current) {
        osdInstanceRef.current.destroy();
      }

      // Initialize OpenSeadragon
      osdInstanceRef.current = OpenSeadragon({
        element: viewerRef.current,
        prefixUrl: "/openseadragon/images/",
        tileSources: {
          type: "image",
          url: imageUrl,
        },
        //tileSources: "https://openseadragon.github.io/example-images/highsmith/highsmith.dzi",
        showNavigator: true,
        defaultZoomLevel: 1,
        minZoomLevel: 0.5,
        maxZoomLevel: 10,
      });
    }

    // Optional cleanup when modal closes or component unmounts
    return () => {
      if (osdInstanceRef.current) {
        osdInstanceRef.current.destroy();
        osdInstanceRef.current = null;
      }
    };
  }, [isOpen, imageUrl]);

  return (
    <ReactModal
      isOpen={isOpen}
      onRequestClose={onRequestClose}
      className="modal-content"
      overlayClassName="modal-overlay"
    >
      <button className="modal-close" onClick={onRequestClose}>
        &times;
      </button>
      <div ref={viewerRef} className="openseadragon-viewer" />
    </ReactModal>
  );
}
